import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface WateringSchedule {
  date: string;
  watered: boolean;
}

interface PlantData {
  plant: {
    name: string;
    nextWatering: string;
    soilMoisture: string;
    lastWatered: string;
  };
  wateringSchedule: WateringSchedule[];
}

export default function Widget() {
  const plantData = response.data as PlantData;
  const lastFiveDays = plantData.wateringSchedule.slice(-5);

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
              {plantData.plant.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Next Watering: {plantData.plant.nextWatering}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Soil Moisture: {plantData.plant.soilMoisture}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Last Watered: {plantData.plant.lastWatered}
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: lastFiveDays.map(day => (day.watered ? 1 : 0)),
                color: '#FFCA28',
                curve: 'step',
                showMark: false,
              },
            ]}
            xAxis={[
              {
                data: lastFiveDays.map(day => day.date),
                hide: true
              }
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {lastFiveDays.map((day, index) => (
              <Chip
                key={index}
                label={day.date}
                color={day.watered ? 'primary' : 'default'}
                sx={{ fontSize: '11px', px: 1 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
